from collections import defaultdict, deque

class Graph:
    def __init__(self):
        self.graph = defaultdict(list)
        self.nodes = set()

    def add_edge(self, u, v):
        self.graph[u].append(v)
        self.nodes.add(u)
        self.nodes.add(v)

    def topological_sort_kahn(self):
        # Calculate indegree for each node
        indegree = {node: 0 for node in self.nodes}
        for u in self.graph:
            for v in self.graph[u]:
                indegree[v] += 1

        # Initialize queue with nodes having indegree 0
        queue = deque([node for node in self.nodes if indegree[node] == 0])
        result = []

        while queue:
            node = queue.popleft()
            result.append(node)

            for neighbor in self.graph[node]:
                indegree[neighbor] -= 1
                if indegree[neighbor] == 0:
                    queue.append(neighbor)

        if len(result) != len(self.nodes):
            return None  # Cycle detected
        return result

# Example usage
if __name__ == "__main__":
    g = Graph()
    # Course prerequisites example (like university courses)
    g.add_edge("Data Structures", "Algorithms")
    g.add_edge("Math", "Algorithms")
    g.add_edge("Algorithms", "Machine Learning")
    g.add_edge("Data Structures", "Database Systems")
    g.add_edge("Math", "Database Systems")

    result = g.topological_sort_kahn()
    print("Topological Order:", result)
